import{_ as t,c as a,o as s,a5 as o}from"./chunks/framework.CgT1UzWm.js";const n="/CA/part1.webp",i="/CA/part2.webp",r="/CA/part3.webp",l="/CA/part5.webp",h="/CA/part7.webp",f=JSON.parse('{"title":"DRAFT: 25 Years of Object–Relational Impedance Mismatch","titleTemplate":"NpgsqlRest","description":"DRAFT — A compilation of a decade of arguments about DDD, Clean Architecture, the wrong abstractions modern business software is built on, and the case for putting the database back where it belongs.","frontmatter":{"layout":"doc","outline":[2,3],"title":"DRAFT: 25 Years of Object–Relational Impedance Mismatch","titleTemplate":"NpgsqlRest","description":"DRAFT — A compilation of a decade of arguments about DDD, Clean Architecture, the wrong abstractions modern business software is built on, and the case for putting the database back where it belongs.","badge":"human","head":[["meta",{"name":"robots","content":"noindex, nofollow"}],["meta",{"name":"keywords","content":"npgsqlrest postgresql clean architecture ddd database-first state abstraction sql platform business rules"}]]},"headers":[],"relativePath":"blog/DRAFT-the-database-is-not-a-detail.md","filePath":"blog/DRAFT-the-database-is-not-a-detail.md"}'),p={name:"blog/DRAFT-the-database-is-not-a-detail.md"};function d(c,e,u,m,g,y){return s(),a("div",null,e[0]||(e[0]=[o(`<h1 id="draft-25-years-of-object–relational-impedance-mismatch" tabindex="-1">DRAFT: 25 Years of Object–Relational Impedance Mismatch <a class="header-anchor" href="#draft-25-years-of-object–relational-impedance-mismatch" aria-label="Permalink to &quot;DRAFT: 25 Years of Object–Relational Impedance Mismatch&quot;">​</a></h1><p class="blog-meta"><span>DRAFT — TODO: date</span> · <span class="tag">NpgsqlRest</span><span class="tag">PostgreSQL</span><span class="tag">Architecture</span><span class="tag">DDD</span><span class="tag">Clean Architecture</span><span class="tag">Opinion</span></p><p><img src="https://img.shields.io/badge/Human-Written-blue" alt=""><img src="https://img.shields.io/badge/DRAFT-orange" alt=""></p><h2 id="some-honesty-upfront" tabindex="-1">Some Honesty Upfront <a class="header-anchor" href="#some-honesty-upfront" aria-label="Permalink to &quot;Some Honesty Upfront&quot;">​</a></h2><p>I have been criticising the modern approach to software engineering — and DDD and Clean Architecture in particular — for over a decade now. Mostly on social media. In short pieces, sometimes with screenshots, sometimes with direct quotes, sometimes with a little bit of sarcasm. Usually all three.</p><p>And then it occurred to me. It has been about 25 years since the term <strong>Object–Relational Impedance Mismatch</strong> entered our vocabulary as the polite, academic way of saying <em>&quot;this isn&#39;t working and we don&#39;t know why.&quot;</em></p><p>A quarter of a century.</p><p>Happy anniversary.</p><p>So I sat down and compiled what I have been writing all this time, and put it in one place — what the misconceptions are, where they came from, what they cost us in practice, and, most importantly, what to do about them.</p><p>This is the long version. Make yourself a coffee.</p><hr><h2 id="those-who-cannot-remember-the-past" tabindex="-1">Those Who Cannot Remember the Past <a class="header-anchor" href="#those-who-cannot-remember-the-past" aria-label="Permalink to &quot;Those Who Cannot Remember the Past&quot;">​</a></h2><p>Did you know that there was an entire movement in software development, complete with its own manifesto, thought leaders, and conferences, dedicated almost exclusively to putting business logic in SQL databases?</p><p>I certainly didn&#39;t, until recently. But it did happen, in the late 1990s and early 2000s.</p><p>Their core philosophy was as follows:</p><ul><li><strong>Data belongs to the organisation, not the application.</strong> Today, we typically call this Bounded Context.</li><li><strong>Rules and constraints should be stored and enforced in the database, not scattered across applications.</strong> Today, we call this the Domain Model. But, in essence, it is just <em>don&#39;t repeat yourself</em> — the database is the source of truth, and there is no point in repeating the same logic across every application, service, and business report.</li><li><strong>Rules should be declarative, in natural language, accessible to a non-technical audience.</strong> Today we say Domain Experts. Same business people.</li><li><strong>Focus on managing business rules, not on hardware and software platforms.</strong> Today we say <em>implementation details</em>. Same idea.</li></ul><p>Does any of this sound familiar?</p><p>There is even a manifesto — the <a href="https://www.businessrulesgroup.org/brmanifesto/BRManifesto.pdf" target="_blank" rel="noreferrer">Business Rules Manifesto</a> — still online. Gartner promoted the idea under the slogan <strong>&quot;change the rules, not the code&quot;</strong> and labelled it as &quot;hot&quot;. Startups built low-code platforms on top of it. Oracle and IBM tried to incorporate it into their rules engines. The movement was hyped, and rightly so.</p><p>And then it fizzled out and almost completely disappeared. Why?</p><p>A few reasons.</p><p><strong>1. The Agile Movement.</strong> Development teams of that era had dedicated DBAs, and a dedicated DBA was supposed to implement business rules in the database, close to the data, in declarative SQL:</p><details class="code-collapsible" open><summary>sql</summary><div class="language-sql vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">sql</span><pre class="shiki shiki-themes catppuccin-latte catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#8839EF;--shiki-dark:#CBA6F7;">ALTER</span><span style="--shiki-light:#8839EF;--shiki-dark:#CBA6F7;"> TABLE</span><span style="--shiki-light:#4C4F69;--shiki-dark:#CDD6F4;"> loans</span></span>
<span class="line"><span style="--shiki-light:#8839EF;--shiki-dark:#CBA6F7;">  ADD</span><span style="--shiki-light:#8839EF;--shiki-dark:#CBA6F7;"> CONSTRAINT</span><span style="--shiki-light:#4C4F69;--shiki-dark:#CDD6F4;"> loans_credit_check</span></span>
<span class="line"><span style="--shiki-light:#8839EF;--shiki-dark:#CBA6F7;">  CHECK</span><span style="--shiki-light:#4C4F69;--shiki-dark:#CDD6F4;"> (</span><span style="--shiki-light:#8839EF;--shiki-dark:#CBA6F7;">NOT</span><span style="--shiki-light:#4C4F69;--shiki-dark:#CDD6F4;"> (</span><span style="--shiki-light:#8839EF;--shiki-dark:#CBA6F7;">status</span><span style="--shiki-light:#179299;--shiki-dark:#94E2D5;"> =</span><span style="--shiki-light:#40A02B;--shiki-dark:#A6E3A1;"> &#39;approved&#39;</span><span style="--shiki-light:#8839EF;--shiki-dark:#CBA6F7;"> AND</span><span style="--shiki-light:#4C4F69;--shiki-dark:#CDD6F4;"> credit_score </span><span style="--shiki-light:#179299;--shiki-dark:#94E2D5;">&lt;</span><span style="--shiki-light:#FE640B;--shiki-dark:#FAB387;"> 650</span><span style="--shiki-light:#4C4F69;--shiki-dark:#CDD6F4;">));</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#8839EF;--shiki-dark:#CBA6F7;">ALTER</span><span style="--shiki-light:#8839EF;--shiki-dark:#CBA6F7;"> TABLE</span><span style="--shiki-light:#4C4F69;--shiki-dark:#CDD6F4;"> users </span><span style="--shiki-light:#8839EF;--shiki-dark:#CBA6F7;">ADD</span><span style="--shiki-light:#8839EF;--shiki-dark:#CBA6F7;"> CONSTRAINT</span><span style="--shiki-light:#4C4F69;--shiki-dark:#CDD6F4;"> users_email_unique </span><span style="--shiki-light:#8839EF;--shiki-dark:#CBA6F7;">UNIQUE</span><span style="--shiki-light:#4C4F69;--shiki-dark:#CDD6F4;"> (email);</span></span>
<span class="line"><span style="--shiki-light:#8839EF;--shiki-dark:#CBA6F7;">ALTER</span><span style="--shiki-light:#8839EF;--shiki-dark:#CBA6F7;"> TABLE</span><span style="--shiki-light:#4C4F69;--shiki-dark:#CDD6F4;"> users </span><span style="--shiki-light:#8839EF;--shiki-dark:#CBA6F7;">ALTER</span><span style="--shiki-light:#4C4F69;--shiki-dark:#CDD6F4;"> COLUMN email </span><span style="--shiki-light:#8839EF;--shiki-dark:#CBA6F7;">SET</span><span style="--shiki-light:#8839EF;--shiki-dark:#CBA6F7;"> NOT NULL</span><span style="--shiki-light:#4C4F69;--shiki-dark:#CDD6F4;">;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br></div></div></details><p>That was not agile enough, obviously. Developers preferred flexibility and speed over centralised governance. The DBAs and the data-centric architects pushing this lost to the agile, app-centric teams. Dedicated DBAs have been a rare breed ever since.</p><p><strong>2. Vendor lock-in.</strong> Centralisation meant locking yourself into proprietary platforms — Oracle, IBM — and paying them forever, because free and open-source alternatives weren&#39;t yet viable. Reasonable concern at the time.</p><p><strong>3. Perceived complexity and weak tooling.</strong> A central, declarative model was perceived as more complex than scattering the same logic across many services. And, to be fair, things we now consider basic — source control, automated testing — weren&#39;t exactly a priority in that centralised RDBMS / BRMS world managed by DBAs.</p><p>So the industry made a choice. The business rules went back into the application layer. And then, because that obviously meant duplicating those rules across applications, services, and reports, we got:</p><ul><li><strong>Service-Oriented Architecture</strong> in the mid-2000s. Centralise the logic in services where programmers have control.</li><li><strong>Microservices</strong> in the 2010s. Scatter the logic across many specialised services.</li><li><strong>Domain-Driven Design</strong>, starting with Eric Evans&#39;s Blue Book in 2003. <em>The rules belong in the Domain Model, not in the database.</em></li><li><strong>Clean Architecture</strong>, popularised by Robert C. Martin in 2017. <em>The rules belong in the architecture core. The database is a detail.</em></li></ul><p>All of which were, in essence, <em>attempts to put the rules back where the Business Rules movement had wanted them in the first place</em> — but now in the application layer, not in the database. Because, you know. The database is a detail.</p><p>Here is the thing. The goals of the Business Rules movement were right. <strong>It was the tools that were inadequate, not the idea.</strong> And we threw the goals out along with the tools.</p><p>And here we are, about 25 years later. Let me list the original objections and check whether they still hold:</p><ul><li><strong>Vendor lock-in?</strong> PostgreSQL is free, open-source, portable, and has a massive ecosystem of support. You are no longer tied to Oracle just to run stored procedures or triggers.</li><li><strong>Scaling?</strong> There are now distributed Postgres-compatible variants — Citus, Timescale, CockroachDB, and several others. Scaling is still hard, but it is no longer a killer.</li><li><strong>Separation of concerns?</strong> Was a misunderstanding from the very beginning. SQL rules are <em>domain semantics</em>. SQL is not storage code by any means.</li><li><strong>Testing and tooling?</strong> pgTAP exists. Migrations in containers, rollback-tests, fixtures. It is a weaker spot than modern app languages with their IDEs and type systems, but it is very much doable and manageable.</li></ul><p>The real gap today is <em>cultural</em>. Developers are trained to think in code-first terms, not data-first. Fewer of us are fluent in SQL as a primary modelling language.</p><p>But we live in 2026, not 2005. The objections that killed the Business Rules movement are no longer load-bearing. The industry just hasn&#39;t caught on yet — and the architectural philosophies it adopted to replace it have, in my opinion, made the original problem worse.</p><p>Let me show you how.</p><hr><h2 id="the-three-misconceptions" tabindex="-1">The Three Misconceptions <a class="header-anchor" href="#the-three-misconceptions" aria-label="Permalink to &quot;The Three Misconceptions&quot;">​</a></h2><p>The way I see it, modern business software is built on three big misconceptions. They are related, they reinforce each other, and they have cascaded into an entire architectural style that delivers, in practice, exactly what the relational database was already going to deliver. With more code. And more bugs.</p><ol><li><strong>State lives in memory.</strong> No. Your state is in your RDBMS.</li><li><strong>The RDBMS abstracts your application.</strong> No. It abstracts your storage. Your application is what you write <em>on top</em> of that.</li><li><strong>SQL doesn&#39;t count.</strong> SQL is the most misunderstood computer language in the world.</li></ol><p>Let me take them one by one.</p><hr><h3 id="misconception-1-—-state-lives-in-the-database" tabindex="-1">Misconception #1 — State Lives in the Database <a class="header-anchor" href="#misconception-1-—-state-lives-in-the-database" aria-label="Permalink to &quot;Misconception #1 — State Lives in the Database&quot;">​</a></h3><p>I found a free chapter from <em>Domain Modeling Made Functional</em>, so I wanted to check whether Functional DDD was any better than the standard OOP DDD.</p><p>No, it is not. It may even be worse.</p><p>The entire premise of that chapter is that something like:</p><details class="code-collapsible" open><summary>sql</summary><div class="language-sql vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">sql</span><pre class="shiki shiki-themes catppuccin-latte catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#8839EF;--shiki-dark:#CBA6F7;">CHECK</span><span style="--shiki-light:#4C4F69;--shiki-dark:#CDD6F4;"> ((IsQuote </span><span style="--shiki-light:#8839EF;--shiki-dark:#CBA6F7;">is</span><span style="--shiki-light:#4C4F69;--shiki-dark:#CDD6F4;"> true) </span><span style="--shiki-light:#8839EF;--shiki-dark:#CBA6F7;">OR</span><span style="--shiki-light:#4C4F69;--shiki-dark:#CDD6F4;"> (IsQuote </span><span style="--shiki-light:#8839EF;--shiki-dark:#CBA6F7;">is</span><span style="--shiki-light:#4C4F69;--shiki-dark:#CDD6F4;"> false </span><span style="--shiki-light:#8839EF;--shiki-dark:#CBA6F7;">AND</span><span style="--shiki-light:#4C4F69;--shiki-dark:#CDD6F4;"> BillingAddressId </span><span style="--shiki-light:#8839EF;--shiki-dark:#CBA6F7;">IS NOT NULL</span><span style="--shiki-light:#4C4F69;--shiki-dark:#CDD6F4;">))</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div></details><p>…is, and I quote, <em>&quot;hard to model&quot;</em>. Well, okay.</p><p>I don&#39;t get it.</p><p>We have this core, fundamental tenet in OOP called <strong>encapsulation</strong>. Encapsulation is supposed to protect internal data — the state. The object is the authoritative custodian of its state. Nobody else has it. Period. Without encapsulation, we don&#39;t really have OOP anymore.</p><p>Functional has its own version — <strong>state immutability</strong>. Functional takes state in the constructor and elegantly returns mutated copies as the result of a function. Same idea — protect inner state, the common source of bugs — but arguably more elegant.</p><p>These are very reasonable, well-thought-out approaches <em>when you have complex states in memory that you need to manage</em>. A complex AST. A game scene graph. A spreadsheet&#39;s formula trees. Whatever.</p><p>Except they don&#39;t work for business applications. At all.</p><p>That shared state lives in a shared, <strong>relational database</strong>. And the database is already doing — and has been doing for forty years — what both of these paradigms are promising. <strong>Encapsulation</strong> (SQL — you don&#39;t poke at pages and tuples directly, you query). <strong>Enforced invariants</strong> (constraints, types, transactions). It already makes illegal states unrepresentable. In real data, not just in code.</p><p>So what does that leave for OOP / Functional in a business app? In the worst case, our internal state is just <strong>plumbing</strong>: connections, queries, transactions, mappings. In the best case, it is <strong>transient state</strong> — chunks of data downloaded from the database, temporarily held in memory.</p><p>The entire premise is broken. There is no internal state to manage other than plumbing for the real state. But instead of admitting that, the response is cognitive dissonance and <strong>doubling down</strong>:</p><ul><li>We need the <strong>Repository pattern</strong> to wrap the database in object syntax and pretend it is a collection.</li><li>When repositories leak relational concerns, the response is <strong>Unit of Work</strong>, to wrap transactions in object syntax.</li><li>When <em>that</em> still leaks, oh no, we need <strong>Aggregate Roots</strong> to redraw consistency boundaries the database was already enforcing.</li><li>When aggregates conflict across services, we need <strong>eventual consistency</strong> and <strong>domain events</strong> — to simulate, in messaging, what the database had as ACID.</li><li>When the system becomes incomprehensible, <strong>CQRS</strong> — to admit that reads and writes are different.</li><li>When CQRS isn&#39;t enough, <strong>event sourcing</strong>. What else. To rebuild a transaction log. AKA the WAL.</li><li>When event sourcing is hard to query, <strong>projections into a read model</strong> — which is, congratulations, <em>a database</em>.</li></ul><p>Each layer is a sophistication and a workaround to deliver what the database was already going to deliver.</p><hr><h3 id="misconception-2-—-the-rdbms-abstracts-storage-not-your-application" tabindex="-1">Misconception #2 — The RDBMS Abstracts Storage, Not Your Application <a class="header-anchor" href="#misconception-2-—-the-rdbms-abstracts-storage-not-your-application" aria-label="Permalink to &quot;Misconception #2 — The RDBMS Abstracts Storage, Not Your Application&quot;">​</a></h3><p>I watched Zoran Horvat&#39;s video <em>&quot;Your DDD Abstractions Are a Waste of Code&quot;</em>. He talks about a common problem of over-abstraction in modern DDD codebases.</p><p>I think the problem with DDD is <strong>NOT (only) over-abstraction</strong>. The problem is <strong>wrong abstraction</strong>.</p><p>Almost every DDD tutorial on the internet shows the same old anti-pattern:</p><ol><li><strong>Get</strong> some data from the repository into memory.</li><li><strong>Change</strong> that data in memory (the Object-Oriented way).</li><li><strong>Put</strong> that data back to the repository.</li></ol><p>The classic <strong>Fetch → Modify → Save</strong> pattern. The primary source of performance bottlenecks and concurrency bugs in enterprise applications. I am sure Zoran would agree we have a race condition and a performance problem with this code.</p><p>If it is wrong, why are all the learning materials showing this?</p><p>Let me pull a direct quote from Eric Evans&#39;s Blue Book — the DDD bible, the foundational text — Chapter 6, <em>The Life Cycle of a Domain Object</em>, the chapter that defines the Repository pattern:</p><blockquote><p><em>&quot;For each type of object that needs global access, create an object that can provide the illusion of an in-memory collection of all objects of that type.&quot;</em></p></blockquote><p>The <strong>illusion of an in-memory collection</strong>. Read that again.</p><p>In the same chapter, he says it <em>&quot;requires a lot of complex technical infrastructure, but the interface is simple.&quot;</em></p><p>What is that complex machinery? Juggling queries, commands, ORMs, mappers. Those are <strong>set operations</strong>.</p><p>Here is the question I would love a DDD expert to answer for me. How does a set operation fit into an in-memory collection? And what problem does an in-memory-collection-like structure solve that our set operations cannot?</p><p>Because modern relational databases do not have data in <em>collections</em> that we can, quote, &quot;emulate&quot;. Data comes in sets, sets of sets, graphs, sets of graphs, graphs of sets, and everything in between. And we have a set-based language to work with all of that. The most refined, mature, and widely deployed language in the entire business world.</p><p>Why are we compelled to compress and abstract and emulate all of that into something we can <em>iterate</em>?</p><p>In my career I have had the opportunity to mentor younger developers on SQL. I don&#39;t particularly like doing it — partly because I am still not confident in my SQL expertise after 30 years, and partly because I don&#39;t like people that much. But I did notice something peculiar:</p><ul><li>Developers trained on imperative languages — Python, Java, C#, whatever — have trouble thinking in sets. When it comes to code, they think in algorithms, memory structures, and iterations. But in SQL, iteration is an anti-pattern. We are required to think in sets. We should never write a procedural loop over our data. That is a no-no. A cursor can have a legitimate use case occasionally, but it is a rare exception.</li><li>They are all overconfident about their SQL — because they have learned CRUD. They have not learned SQL. Classic Dunning–Kruger. And then you give them something slightly more complex and they all go <code>FOREACH LOOP</code> on you with some procedural extension.</li></ul><p>So when the Blue Book says <em>create the illusion of an in-memory collection</em> — what it is really doing is letting the developer keep iterating, in the language they are comfortable with, <strong>over data that is supposed to live in sets in a database</strong>. The Repository pattern is a comfort blanket. Nothing more.</p><p>Modern relational databases are already abstracting storage. DDD wants to treat them <em>as</em> storage — the thing those databases are already abstracting away. And since we are treating them as storage, that means treating them as a <em>repository</em>: the thing we put data into and retrieve data from.</p><p>That is precisely why virtually every example follows the same inefficient, race-condition-riddled pattern. They treat everything as a <em>collection of objects</em>; objects live in memory; the relational database is just a backup. A repository. Almost a file system. Instead of what it truly is: <strong>a set-based logic engine that does your storage abstraction for you</strong>.</p><p>These examples are not simplifications. They are <em>ramifications</em> of that wrong abstraction. As far as the relational database is concerned, there is neither <em>storage</em> nor <em>repository</em> — those are buried deep in the implementation, not something users or database clients should ever be concerned with.</p><p>There are <strong>relational sets</strong>. That is why <code>update &lt;set&gt; set &lt;value&gt; where &lt;…&gt;</code> is natural there, and the repository approach is not.</p><p>These are not <em>Patterns of Persistence</em>, as modern DDD calls them. <strong>These are Patterns of Data Displacement.</strong> They unnecessarily move data where it doesn&#39;t belong — memory — just to be able to use clean C# (or whatever) syntax. Notice how DDD never wants to abstract the <em>memory device</em>. Only the <em>storage</em>. Well…</p><hr><h3 id="misconception-3-—-sql-is-the-most-misunderstood-computer-language" tabindex="-1">Misconception #3 — SQL Is the Most Misunderstood Computer Language <a class="header-anchor" href="#misconception-3-—-sql-is-the-most-misunderstood-computer-language" aria-label="Permalink to &quot;Misconception #3 — SQL Is the Most Misunderstood Computer Language&quot;">​</a></h3><p>Software architecture for business applications has been in a permanent state of cognitive dissonance for decades. Let me put two facts next to each other and see if you can make them make sense.</p><p><strong>Fact one.</strong> SQL is the undisputed crowned king of computer languages in the business world. There is no doubt about that. Every business application of any consequence, anywhere on the planet, has an SQL database underneath it. Forty years of refinement. Trillions of dollars of value moving through it every day.</p><p><strong>Fact two.</strong> We are not supposed to use it in our business applications at all. We are not allowed to write any business logic with it.</p><p>Unless we want to be shamed for how inadequate and bad our software architecture is — because we used the <em>computer language of business</em> in our business application.</p><p><strong>Make it make sense.</strong></p><p>And here is the part that I find the most disorienting. We are following software architecture and design guidelines for our SQL-backed business systems from a person who clearly states, and <em>rants</em>, that he doesn&#39;t want to use SQL databases at all.</p><p>Direct quote, from <em>Clean Architecture</em>:</p><blockquote><p><em>&quot;Why in the world would I want to rearrange my linked lists and trees into a bunch of rows and tables accessed through SQL? Why would I introduce all the overhead and expense of a massive RDBMS when a simple random access file system was more than sufficient?&quot;</em></p></blockquote><p>And, more recently — May 2025:</p><blockquote><p><em>&quot;SQL was never intended to be used by computer programs. It was a console language for printing reports. Embedding it into programs was one of the gravest errors of our industry.&quot;</em></p></blockquote><p>Right. Let&#39;s follow this man&#39;s advice on how to design a business system backed by an SQL database.</p><p>SQL has been refined for forty years. It is the <strong>primary interface</strong> to your PostgreSQL database, and it lets you use PostgreSQL&#39;s capabilities to the fullest extent.</p><p>And we are going to swap it out for the HTTP protocol? Or for something completely new like GraphQL? Really?</p><p>How does that measure in terms of expressiveness and the power of the PostgreSQL implementation? How does that make any sense from an architectural standpoint?</p><p>It doesn&#39;t. We just don&#39;t say that part out loud.</p><hr><h2 id="what-this-costs-in-practice" tabindex="-1">What This Costs In Practice <a class="header-anchor" href="#what-this-costs-in-practice" aria-label="Permalink to &quot;What This Costs In Practice&quot;">​</a></h2><p>So the three misconceptions are: state lives in memory, the database is storage, and SQL doesn&#39;t count. Let me show you what we actually <em>pay</em> for them, in real engineering terms.</p><h3 id="three-type-systems-that-don-t-talk-to-each-other" tabindex="-1">Three Type Systems That Don&#39;t Talk to Each Other <a class="header-anchor" href="#three-type-systems-that-don-t-talk-to-each-other" aria-label="Permalink to &quot;Three Type Systems That Don&#39;t Talk to Each Other&quot;">​</a></h3><p>The modern development stack is literally crazy. It is insane.</p><p>Take any modern business web application — let&#39;s say a .NET / Angular stack running on PostgreSQL. We have three separate type systems, and they don&#39;t particularly like each other.</p><p><strong>1. The PostgreSQL type system.</strong> I would argue easily that it is the richest of the three. Separate subject for another day. In any case, we might have something like:</p><details class="code-collapsible" open><summary>sql</summary><div class="language-sql vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">sql</span><pre class="shiki shiki-themes catppuccin-latte catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#4C4F69;--shiki-dark:#CDD6F4;">INVOICE_NUMBER </span><span style="--shiki-light:#8839EF;--shiki-dark:#CBA6F7;">TEXT</span><span style="--shiki-light:#8839EF;--shiki-dark:#CBA6F7;"> NOT NULL</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div></details><p>There might even be a CHECK constraint on the shape of that text, but let&#39;s keep it simple.</p><p><strong>2. The C# / .NET type system.</strong> Same thing, now expressed as:</p><details class="code-collapsible" open><summary>csharp</summary><div class="language-csharp vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">csharp</span><pre class="shiki shiki-themes catppuccin-latte catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#8839EF;--shiki-dark:#CBA6F7;">public</span><span style="--shiki-light:#8839EF;--shiki-dark:#CBA6F7;"> string</span><span style="--shiki-light:#4C4F69;--shiki-dark:#CDD6F4;"> InvoiceNumber </span><span style="--shiki-light:#7C7F93;--shiki-dark:#9399B2;">{</span><span style="--shiki-light:#4C4F69;--shiki-dark:#CDD6F4;"> get</span><span style="--shiki-light:#7C7F93;--shiki-dark:#9399B2;">;</span><span style="--shiki-light:#4C4F69;--shiki-dark:#CDD6F4;"> set</span><span style="--shiki-light:#7C7F93;--shiki-dark:#9399B2;">;</span><span style="--shiki-light:#7C7F93;--shiki-dark:#9399B2;"> }</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div></details><p>That string might be <code>null</code>, by the way. In PostgreSQL it literally cannot ever be null.</p><p><strong>3. The TypeScript type system on your frontend.</strong> Same thing, one more time:</p><details class="code-collapsible" open><summary>typescript</summary><div class="language-typescript vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">typescript</span><pre class="shiki shiki-themes catppuccin-latte catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#4C4F69;--shiki-dark:#CDD6F4;">invoiceNumber</span><span style="--shiki-light:#7C7F93;--shiki-dark:#9399B2;">:</span><span style="--shiki-light:#4C4F69;--shiki-dark:#CDD6F4;"> string</span><span style="--shiki-light:#7C7F93;--shiki-dark:#9399B2;">;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div></details><p>But, in practice, as we all know, it might be <code>null</code>. Or <code>undefined</code>. Who knows. No one knows.</p><p>And it gets worse. We don&#39;t just have three separate, mutually incompatible type systems for the same logical thing. Depending on your design — looking at you, DDD — we have anywhere from <strong>three to five separate implementations</strong> of the same logical model: domain entity, persistence entity, request DTO, response DTO, ViewModel. In three incompatible type systems. That all have to be stitched together and kept in perfect sync, at all times, or your software doesn&#39;t run correctly.</p><p><strong>Holy cognitive load, Batman.</strong></p><p>Insane, isn&#39;t it? And here is the kicker — we do this to <em>simplify maintainability</em>. It is not even funny at this point.</p><p>To be fair, there are serious attempts in the industry to sort out at least the backend-to-frontend mess. Stacks like SvelteKit, Next.js, Nuxt, and Blazor let you reuse the same models on both sides of the wire. That is something. But all of those stacks ignore the database part entirely. Your PostgreSQL schema can still drift without anyone noticing, and you have to keep it in sync by hand — adjust the code, write the migration, update the model, hope you got it right.</p><p>The friction is real. Type systems, model mapping, naming conventions, the works. The compiler is not going to save you.</p><h3 id="a-1000-record-performance-audit" tabindex="-1">A 1000-Record Performance Audit <a class="header-anchor" href="#a-1000-record-performance-audit" aria-label="Permalink to &quot;A 1000-Record Performance Audit&quot;">​</a></h3><p>Have you ever wondered what actually happens when you pull 1000 records out of PostgreSQL and send them down the HTTP wire to your frontend?</p><p>Let me count the iterations.</p><ol><li><strong>PostgreSQL builds the result set.</strong> The executor materialises 1000 tuples from heap or index access. That is the first 1000-times iteration, inside the database.</li><li><strong>PostgreSQL serialises the result to the wire protocol and sends it to the client.</strong> The client driver — Npgsql, psycopg — reads from the incoming stream, and the ORM allocates 1000 objects into a memory list. That is the second 1000-times iteration, fused with the consumer&#39;s read loop. And 1000 memory allocations.</li><li><strong>Convert the in-memory list to a DTO.</strong> In a standard <code>eShopOnWeb</code>-style template, that is mapping <code>List&lt;CatalogItem&gt;</code> to <code>List&lt;CatalogItemDto&gt;</code>. In Python, <code>CatalogItemDto.model_validate(item)</code> for each entity. That is the third 1000-times iteration. Another 1000 allocations.</li><li><strong>JSON serialisation.</strong> The fourth and final 1000-times iteration. Depending on the serialiser, possibly another 1000 allocations on top.</li></ol><p>So for 1000 records over the wire — <em>pulls out the calculator</em> — that is <strong>four thousand iterations, two thousand memory allocations, and one network call</strong> to PostgreSQL, before the JSON response even leaves the server.</p><p>Such a waste of resources. And I haven&#39;t even started on what happens <em>before</em> the database request — the controller, the validation, the request DTO, the unit-of-work, the repository, the query builder.</p><p>This is the price of the three misconceptions. It is paid by every request, by every user, on every page.</p><hr><h2 id="the-database-is-a-detail-—-a-critique" tabindex="-1">&quot;The Database Is a Detail&quot; — A Critique <a class="header-anchor" href="#the-database-is-a-detail-—-a-critique" aria-label="Permalink to &quot;&quot;The Database Is a Detail&quot; — A Critique&quot;">​</a></h2><p>Now let me get to the book that pushed all of this into the mainstream. <em>Clean Architecture: A Craftsman&#39;s Guide to Software Structure and Design</em>, Robert C. Martin, 2017. Chapter 30: <strong>The Database Is a Detail</strong>.</p><p>This is my analysis, originally published as a series of posts. I am going to compress it here.</p><h3 id="part-1-intro" tabindex="-1">Part 1: Intro <a class="header-anchor" href="#part-1-intro" aria-label="Permalink to &quot;Part 1: Intro&quot;">​</a></h3><p><img src="`+n+'" alt=""></p><p>The claim is that the database is a non-entity when it comes to architecture. Basically, it is as important as the design of a doorknob is to the architecture of your home. And you are a bad software designer if you <em>&quot;allow low-level mechanisms to pollute the system architecture.&quot;</em></p><p>Nothing could be further from the truth.</p><p>Which database to use in your system — and he is talking <em>here</em> about that, not about data modelling — is one of the most important decisions you can make. It has long-term consequences.</p><p>There are so many considerations that come into this decision that it is hard to count them all:</p><ul><li>Are we going to have <strong>analytical processing</strong> needs? We may have to look at specialised OLAP databases like Snowflake or ClickHouse.</li><li>Are we going to have <strong>real-time transactional</strong> or transaction-heavy needs? CockroachDB, DynamoDB.</li><li>Are general-purpose databases — PostgreSQL, SQL Server, MySQL — good enough for our requirements?</li><li>Some of those do one thing better and another thing just barely. How does that match our requirements?</li><li>Can we use a combination and get the best of all worlds? How much complexity penalty do we pay?</li><li>What about <strong>graph and tree</strong> processing? How much hierarchical data?</li><li>Do we have <strong>search</strong> features, and over what type and amount of data?</li><li>What about <strong>scaling</strong>? Read-only request scaling, write-only, or both? The wrong decision will haunt you.</li></ul><p>…and on and on.</p><p>Doorknob, you say?</p><h3 id="part-2-relational-databases" tabindex="-1">Part 2: Relational Databases <a class="header-anchor" href="#part-2-relational-databases" aria-label="Permalink to &quot;Part 2: Relational Databases&quot;">​</a></h3><p><img src="'+i+'" alt=""></p><p>In this part, Martin discusses <em>relational databases</em> to prove his point that databases — and in particular relational databases, because I don&#39;t see him even mention any other kind — are, in fact, a detail.</p><p>The problem in this chapter is that <strong>Edgar Codd did not define the principles of relational databases — he defined the principles of the <em>relational model</em>.</strong></p><p>It may sound like a small nitpick, but it is an extremely important distinction. The relational model has nothing to do with technology. It is neither the data storage nor the access technology of any kind. It is a relational <em>model</em> of data, which later became the theoretical foundation for relational databases. Codd did not define the principles of relational databases — which involve things like indexing, concurrency control, etc.</p><p>It is based on mathematics — set theory, relational calculus, relational algebra. That is why it is so elegant and robust, as Martin himself points out.</p><p>If you start from the wrong premise, what will your conclusions be?</p><p>Later he goes on to say it is an architectural error to pass relational data (rows and tables) into your application, because <em>&quot;it couples use cases, business rules, and in some cases even the UI to the relational structure of the data.&quot;</em></p><p>I am truly failing to understand this. Relational data has tuples (rows) and attributes (name, email, amount, type — whatever). Why would it be an error to use your data structured for your use case? If my users have invoices, they would want to see invoices in rows, with their amount, date, customer.</p><p><strong>Is it an error to use your own data?</strong></p><p>He doesn&#39;t explain. And he doesn&#39;t say what the alternative would be. Maybe in the next part…</p><h3 id="part-3-why-are-database-systems-so-prevalent" tabindex="-1">Part 3: Why Are Database Systems So Prevalent? <a class="header-anchor" href="#part-3-why-are-database-systems-so-prevalent" aria-label="Permalink to &quot;Part 3: Why Are Database Systems So Prevalent?&quot;">​</a></h3><p><img src="'+r+'" alt=""></p><p>We start with a flawed premise: <em>&quot;Databases Only Exist Because of Disks.&quot;</em> Disks are slow. Therefore, with the disappearance of disks, databases will become irrelevant.</p><p>That is outright not true.</p><p>Databases are not <em>just</em> mitigating disk slowness — they are doing data integrity, transactional correctness, concurrency control, security, optimisation, and primarily acting as a <strong>reliable source of truth</strong> for your system.</p><p>Memory is volatile. It is gone forever when the process exits. You can&#39;t rely on memory. Different parts of the application (or applications) usually need a different view of the same data. Therefore there is a need for a single source of truth, structured in an accessible and predictable way, that eliminates redundancies and anomalies.</p><p>Those things have nothing to do with <em>disks</em>.</p><p>Quote: <em>&quot;To mitigate the time delay imposed by disks, you need indexes.&quot;</em></p><p>Let&#39;s say we have built a memory structure — a linked list, a hash table — that holds invoices. We have a lot of them. A gigabyte or two. We need to find all invoices with amount equal to 100. Iteration takes too long.</p><p>I know, maybe we can build a balanced binary tree memory structure — what a great idea. This structure would help us avoid all those costly iterations. We can call it just <em>B-Tree</em> for short.</p><p>…and how do you think those indexes work?</p><p>I am not trying to be too facetious here, but this is a fundamental misunderstanding of how indexes work and why they exist.</p><p>If we also added concurrency control so multiple threads and processes could access our search tree, and a mechanism to transfer to and retrieve from non-volatile memory (a.k.a. storage), and exposed all of it through some kind of language — you see where I am going.</p><p><strong>Indexes have nothing to do with disks.</strong> There are many kinds of indexes, and they all implement different structures.</p><p>It seems Martin has some kind of beef with relational databases in particular. He doesn&#39;t even mention document databases — those exist too, and there is a big use case for them. And not to mention that relational databases can store, retrieve, and index documents efficiently.</p><h3 id="part-5-details-and-but-what-about-performance" tabindex="-1">Part 5: Details, and &quot;But What About Performance?&quot; <a class="header-anchor" href="#part-5-details-and-but-what-about-performance" aria-label="Permalink to &quot;Part 5: Details, and &quot;But What About Performance?&quot;&quot;">​</a></h3><p><img src="'+l+'" alt=""></p><p>In these two parts, Martin is basically summarising his false premises:</p><ul><li>A database is <em>&quot;just a mechanism to move the data back and forth between the surface of the disk and the RAM.&quot;</em></li><li><em>&quot;Nothing more than big buckets of bits we store our data on a long-term basis.&quot;</em></li></ul><p>For him, databases are indistinguishable from storage devices.</p><p>When you start from premises like these, the conclusion is going to be wrong. <em>&quot;We should not care about the form that the data takes while it is on the surface of a rotating magnetic disk&quot;</em> — sure, certainly true. And <strong>that is why we use databases</strong>. Their engines take care of that for us, so we don&#39;t have to.</p><p>But then: <em>&quot;…when it comes to data storage, it&#39;s a concern that can be entirely encapsulated and separated from the business rules.&quot;</em></p><p>Here is the false assumption again. <strong>The database is not data storage</strong> — it takes care of the storage concern for us.</p><p>Virtually all databases regularly collect statistics about your data — shape, volume, everything. Why so many statistics? When the database receives a request (a query), it uses those statistics to find the <strong>optimal algorithm and the most appropriate data structure</strong> for the stated intent.</p><p>Think about that for a second. It will find the most suitable algorithm — accompanied by an appropriate data structure — for your declared intent, and then execute it for you.</p><p>So, in practice: not only is storage abstracted, but <strong>so are the algorithms and data structures</strong>. To an extent, of course — it is a leaky abstraction, but an abstraction nevertheless.</p><p>It means operators are relieved from lower-level concerns: storage devices, algorithms, data structures. SQL and similar declarative tools are <em>higher-level</em> than what Martin counts as <em>&quot;low-level data access mechanisms.&quot;</em></p><p>And most importantly — if you are relieved from all of that — storage, memory, algorithms, data structures — what is left?</p><p>That&#39;s right. <strong>The business rules.</strong> The business logic. You know, the things your clients and users actually care about.</p><h3 id="part-6-the-anecdote" tabindex="-1">Part 6: The Anecdote <a class="header-anchor" href="#part-6-the-anecdote" aria-label="Permalink to &quot;Part 6: The Anecdote&quot;">​</a></h3><p>In my opinion, anecdotes can be a very powerful persuasion technique. Nothing like a good anecdote to prove I am right and you are wrong. Although it is still a logical fallacy.</p><p>Martin tells a story. Almost everyone on his team — clients, marketing, hardware engineers — wanted him to use an RDBMS. He fought back. He wanted to keep the data in memory and save and load it to and from raw files instead.</p><p>His hardware engineer, quote: <em>&quot;held meetings behind my back with the executives&quot;</em> and <em>&quot;claimed that RDBMS was somehow more reliable than the random access files that we were using&quot;</em> — implying that an RDBMS doesn&#39;t provide any reliability advantage over the file system.</p><p>Here is the problem. <strong>His hardware engineer was right.</strong></p><p>Databases are built to ensure durability, atomicity, and consistency, even under the worst conditions. You can be left with corrupted or incomplete data when you save your linked lists to files. Databases use a myriad of incredibly sophisticated techniques — Write-Ahead Log, checkpoints, recovery protocols, snapshots, two-phase commit, crash recovery — all to avoid partial writes and corruption. Decades of work by very talented people.</p><p>If you use a file system instead, you would have to re-implement all of those features yourself just to achieve a comparable level of reliability. A lifetime of programming. Questionable result.</p><blockquote><p><em>&quot;I stuck to my engineering principles in the face of incredible ignorance.&quot;</em></p></blockquote><p>No. You refused to admit you were wrong.</p><p>I&#39;d like to take a step back and give Martin some benefit of the doubt:</p><ul><li>Marketing should not be involved in this kind of decision.</li><li>Modern software development marketing is absolutely atrocious. It consistently corrupts the entire industry. All for money.</li></ul><p>That doesn&#39;t mean we shouldn&#39;t be open to rational arguments.</p><p>In the end, Martin quit and became a consultant. Funny part — so did I. And like Martin, I have a similar anecdote. The only difference is I was on the other side of the argument. But I lost too — maybe thanks to this book — and became a consultant.</p><h3 id="part-7-conclusion" tabindex="-1">Part 7: Conclusion <a class="header-anchor" href="#part-7-conclusion" aria-label="Permalink to &quot;Part 7: Conclusion&quot;">​</a></h3><p><img src="'+h+'" alt=""></p><p>There is not much to be said about the conclusion. It just repeats the same wrong assumptions and the same wrong conclusions from the previous parts.</p><p>A lie repeated many times doesn&#39;t become a truth — no more than a database becomes a <em>&quot;storage device&quot;</em>. But it does create the illusion of one.</p><p>So I asked an AI to estimate how much of an impact this book has had on business software development.</p><blockquote><p>Explicit Adoption: ~20–30% of modern business software projects (especially in enterprise, microservices, complex domains) explicitly follow Clean Architecture&#39;s structure.</p><p>Implicit/Partial Adoption: ~70–80% incorporate at least some of its principles.</p></blockquote><p><strong>Approximately 20–30% of modern business software projects explicitly follow Clean Architecture.</strong></p><p>And you thought <em>vibe coding</em> was bad.</p><p>Maybe not all of those involved have a lack of understanding of database fundamentals. But in that case they have a lack of understanding of what the architecture book they follow is trying to teach. I don&#39;t know how many times I have encountered digital content showing the famous concentric circles of Clean Architecture with no database system in sight at all — in blogs, posts, any type of content. <strong>All virtue signaling, zero understanding.</strong></p><p>To rephrase the original quote: <em>&quot;If you think good architecture is expensive, try Clean Architecture.&quot;</em></p><hr><h2 id="postgresql-as-a-platform-—-and-why-existing-tools-miss" tabindex="-1">PostgreSQL as a Platform — and Why Existing Tools Miss <a class="header-anchor" href="#postgresql-as-a-platform-—-and-why-existing-tools-miss" aria-label="Permalink to &quot;PostgreSQL as a Platform — and Why Existing Tools Miss&quot;">​</a></h2><p>OK. So if the database is <em>not</em> a detail, and SQL is the public interface, and &quot;state&quot; lives there — what should the tool stack look like?</p><p>There are solutions out there that already treat PostgreSQL as a platform. Let&#39;s check them one by one.</p><p><strong>PostgREST</strong> will introspect schema <em>tables and views</em> and generate HTTP endpoints. It basically lets you define logic in your HTTP protocol — filters, sorts, etc., in your request parameters, query string, JSON body. I know, I know, they will say it is a <em>query specification</em>, not logic. Yeah, right. <strong>It is the logic.</strong></p><p>And when that doesn&#39;t work — not surprisingly — they have PostgreSQL functions and procedures as an escape hatch.</p><p><strong>Supabase</strong> is a platform built on PostgREST. Same thing.</p><p><strong>PostGraphile</strong> and <strong>Hasura</strong> will introspect schema tables and views and generate a GraphQL grammar — with all the problems that GraphQL brings to the table (table — get it, pun intended).</p><p>The common thread: they all expose your <strong>tables</strong> through HTTP or GraphQL. But your tables are your <strong>state data</strong>. That is the <em>private</em> part. It should be encapsulated and absolutely protected.</p><p><strong>SQL statements</strong> — or, more strictly, <strong>functions and procedures</strong> — are your public interface.</p><p>That is a different philosophy. And it is why I had to build my own tool.</p><hr><h2 id="but-what-problem-does-it-solve" tabindex="-1">But What Problem Does It Solve? <a class="header-anchor" href="#but-what-problem-does-it-solve" aria-label="Permalink to &quot;But What Problem Does It Solve?&quot;">​</a></h2><p>This is the question I learned to ask from the wisest manager I have ever worked with. If a developer couldn&#39;t clearly articulate the answer, the proposal and the code were rejected. It shaped how I think about software development to this day. If I can&#39;t answer <em>what problem does it solve</em> — it should not exist. Period.</p><p>So, what problem does <strong>NpgsqlRest</strong> solve?</p><p>I spent two years of my life building this tool, for my own needs. Let me give you the numbers from a real project.</p><ul><li><strong>3,287 lines of TypeScript fetch typed clients</strong>, auto-generated on every build.</li><li><strong>1,156 lines of TypeScript models</strong> for those requests and responses, auto-generated.</li><li><strong>1,804 lines of HTTP client files</strong> for testing, auto-generated.</li><li><strong>74 endpoints × ~40–80 lines of per-endpoint C#</strong> that I never had to write — controllers, repositories, services, DI registrations. That is roughly 3,000 to 6,000 lines of imperative C# that simply does not exist in the project. About 220–370 files that don&#39;t exist.</li><li><strong>305 lines of declarative JSON</strong> absorbing infrastructure plumbing that would otherwise be roughly 550–1,300 lines of imperative C#: auth, SSE, caching, rate limiting, health checks, security headers, OpenAPI, retries, CORS, antiforgery, response compression.</li></ul><p>Grand total, conservative numbers: about <strong>6,247 lines of auto-generated artefacts in the repo</strong>, plus <strong>3,500 to 7,300 lines of C# I never had to write</strong>, plus <strong>55 to 100 hours of typing I never had to do</strong>.</p><p>Now think about what happens when requirements change. As they always do. Sometimes, honestly, I don&#39;t even understand them — sometimes it is just bad communication, it happens. Anyone who has worked in this industry knows this very well. So entire parts need to be changed, sometimes rewritten from scratch.</p><p>How long would it take me to keep up with all those changes in a traditional setup? Even with AI tools — how many tokens would I have burned regenerating boilerplate? How many bugs would I have written in the process?</p><p>NpgsqlRest solves what I now consider the most expensive problem in software development: <strong>the cost of changing your mind.</strong></p><p>I can iterate 5–10× faster. And give my users exactly what they want.</p><p>There is one and only one source of truth in this system, and that is the PostgreSQL database. Not two. Not three. <strong>One.</strong> If you need to check the type of something, you go to the database. If you need to check a constraint, you go to the database. The TypeScript client module is regenerated on every build. There can be no drift. No mismatch. No room for error. Ever. Period.</p><p>And because there are no DTOs, no mappers, no ORM, no domain entities — the request path is direct. PostgreSQL serialises the result to its wire protocol. NpgsqlRest reads from the PostgreSQL stream and writes directly to the HTTP response stream. <strong>Two iterations instead of four. Zero allocations on the application side. One network call.</strong></p><p>My own benchmark puts NpgsqlRest at roughly <strong>2.6× PostgREST</strong> on a fair fight — both serving identical SQL, no DTOs, no mappers. That is the framework-overhead gap.</p><p><strong>The architecture-overhead gap, on the other hand, isn&#39;t even measured.</strong></p><p>That is what NpgsqlRest never introspects. It does not look at your schema. It does not generate endpoints from your tables. What it <em>does</em> introspect is either:</p><ul><li>your <strong>PostgreSQL functions and procedures</strong>, or</li><li>your <strong>PostgreSQL SQL script files</strong>,</li></ul><p>…depending on your preferred approach. And then exposes that as an automatic REST endpoint. Your tables, your types, your relational structure — that is private. SQL statements, functions, and procedures are your public interface.</p><p>That&#39;s it. That is the whole philosophy.</p><hr><h2 id="conclusion" tabindex="-1">Conclusion <a class="header-anchor" href="#conclusion" aria-label="Permalink to &quot;Conclusion&quot;">​</a></h2><p>DDD treats memory as the source of truth. Clean Architecture treats the database as a doorknob. PostgREST and friends treat your schema as your API.</p><p>All three are wrong, in slightly different ways. NpgsqlRest is what you get when you reject all three premises at once.</p><p>The Business Rules movement had the right idea 25 years ago. The tools weren&#39;t there. They are now. The only thing left in the way is <strong>culture</strong> — and culture, in the end, is just a habit. Habits change.</p><p>To paraphrase Star Wars:</p><p><strong>NOW WITNESS THE FIREPOWER OF THIS FULLY ARMED AND OPERATIONAL POSTGRESQL STATION.</strong></p>',237)]))}const w=t(p,[["render",d]]);export{f as __pageData,w as default};
